PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE estat_metainfo (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  stats_data_id TEXT NOT NULL,           
  stat_name TEXT NOT NULL,               
  title TEXT NOT NULL,                   
  cat01 TEXT,                            
  item_name TEXT,                        
  unit TEXT,                             
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,  
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP   
, ranking_key TEXT);
CREATE TABLE ranking_visualizations (
  id INTEGER PRIMARY KEY AUTOINCREMENT,

  
  stats_data_id TEXT NOT NULL,         
  cat01 TEXT NOT NULL,                 

  
  map_color_scheme TEXT DEFAULT 'interpolateBlues',
  map_diverging_midpoint TEXT DEFAULT 'zero',

  
  ranking_direction TEXT DEFAULT 'desc', 

  
  conversion_factor REAL DEFAULT 1,    
  decimal_places INTEGER DEFAULT 0,    

  
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,

  
  UNIQUE(stats_data_id, cat01)
);
CREATE TABLE choropleth_categories (
  id TEXT PRIMARY KEY,                        
  name TEXT NOT NULL,                         
  description TEXT,                           
  icon TEXT,                                  
  color TEXT,                                 
  display_order INTEGER NOT NULL DEFAULT 0,  
  is_active BOOLEAN DEFAULT 1,               
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE choropleth_subcategories (
  id TEXT PRIMARY KEY,                        
  category_id TEXT NOT NULL,                  
  name TEXT NOT NULL,                         
  description TEXT,                           
  unit TEXT NOT NULL,                         
  data_type TEXT NOT NULL CHECK(data_type IN ('numerical', 'percentage', 'rate')), 
  stats_data_id TEXT,                         
  table_name TEXT,                            
  color_scheme TEXT,                          
  display_order INTEGER NOT NULL DEFAULT 0,  
  is_active BOOLEAN DEFAULT 1,               
  last_updated DATETIME,                      
  available_years TEXT,                       
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (category_id) REFERENCES choropleth_categories(id) ON DELETE CASCADE
);
CREATE TABLE choropleth_data_cache (
  id TEXT PRIMARY KEY,                        
  subcategory_id TEXT NOT NULL,              
  year TEXT NOT NULL,                         
  data JSON NOT NULL,                         
  metadata JSON,                              
  source TEXT,                                
  is_sample BOOLEAN DEFAULT 0,               
  cached_at DATETIME DEFAULT CURRENT_TIMESTAMP,  
  expires_at DATETIME,                        
  access_count INTEGER DEFAULT 0,            
  last_accessed_at DATETIME DEFAULT CURRENT_TIMESTAMP, 
  FOREIGN KEY (subcategory_id) REFERENCES choropleth_subcategories(id) ON DELETE CASCADE,
  UNIQUE(subcategory_id, year)                
);
CREATE TABLE prefectures (
  code TEXT PRIMARY KEY,                      
  name TEXT NOT NULL,                         
  region TEXT,                                
  capital TEXT,                               
  area_km2 REAL,                             
  population INTEGER,                         
  population_year TEXT,                       
  is_active BOOLEAN DEFAULT 1,               
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE choropleth_access_logs (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  subcategory_id TEXT,                        
  year TEXT,                                  
  user_ip TEXT,                              
  user_agent TEXT,                           
  response_time_ms INTEGER,                   
  cache_hit BOOLEAN DEFAULT 0,               
  error_message TEXT,                         
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (subcategory_id) REFERENCES choropleth_subcategories(id) ON DELETE SET NULL
);
CREATE TABLE choropleth_user_settings (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  user_id INTEGER,                            
  favorite_categories TEXT,                   
  favorite_subcategories TEXT,               
  default_color_scheme TEXT DEFAULT 'interpolateBlues', 
  default_year TEXT,                          
  settings JSON,                              
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
  UNIQUE(user_id)                             
);
CREATE TABLE estat_categories (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  
  
  stats_data_id TEXT NOT NULL,
  category_code TEXT NOT NULL,
  
  
  category_name TEXT NOT NULL,
  display_name TEXT NOT NULL,
  unit TEXT,
  
  
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  
  
  UNIQUE(stats_data_id, category_code)
);
CREATE TABLE estat_time_periods (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  
  
  stats_data_id TEXT NOT NULL,
  time_code TEXT NOT NULL,
  
  
  time_name TEXT NOT NULL,
  year INTEGER,  
  
  
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  
  
  UNIQUE(stats_data_id, time_code)
);
CREATE TABLE estat_cache_metadata (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  
  
  stats_data_id TEXT NOT NULL,
  category_code TEXT NOT NULL,
  time_code TEXT NOT NULL,
  
  
  record_count INTEGER NOT NULL,           
  has_valid_values BOOLEAN DEFAULT 1,      
  
  
  cache_hit_count INTEGER DEFAULT 0,       
  last_accessed_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  
  
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  expires_at DATETIME,                     
  
  
  UNIQUE(stats_data_id, category_code, time_code)
);
CREATE TABLE subcategory_configs (
  id TEXT PRIMARY KEY,              
  category_id TEXT NOT NULL,        
  name TEXT NOT NULL,               
  description TEXT,
  default_ranking_key TEXT,         
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE IF NOT EXISTS "ranking_items_old_backup" (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  subcategory_id TEXT NOT NULL,     
  ranking_key TEXT NOT NULL,        
  label TEXT NOT NULL,              
  stats_data_id TEXT NOT NULL,      
  cd_cat01 TEXT NOT NULL,           
  unit TEXT NOT NULL,               
  name TEXT NOT NULL,               
  display_order INTEGER DEFAULT 0,
  is_active BOOLEAN DEFAULT 1,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(subcategory_id, ranking_key)
);
CREATE TABLE users (
  id TEXT PRIMARY KEY,
  name TEXT,
  email TEXT UNIQUE NOT NULL,
  emailVerified DATETIME,
  image TEXT,
  username TEXT UNIQUE,
  password_hash TEXT,
  role TEXT DEFAULT 'user',
  is_active BOOLEAN DEFAULT 1,
  last_login DATETIME,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE accounts (
  id TEXT PRIMARY KEY,
  userId TEXT NOT NULL,
  type TEXT NOT NULL,
  provider TEXT NOT NULL,
  providerAccountId TEXT NOT NULL,
  refresh_token TEXT,
  access_token TEXT,
  expires_at INTEGER,
  token_type TEXT,
  scope TEXT,
  id_token TEXT,
  session_state TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (userId) REFERENCES users(id) ON DELETE CASCADE
);
CREATE TABLE sessions (
  id TEXT PRIMARY KEY,
  sessionToken TEXT UNIQUE NOT NULL,
  userId TEXT NOT NULL,
  expires DATETIME NOT NULL,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (userId) REFERENCES users(id) ON DELETE CASCADE
);
CREATE TABLE verification_tokens (
  identifier TEXT NOT NULL,
  token TEXT NOT NULL,
  expires DATETIME NOT NULL,
  PRIMARY KEY (identifier, token)
);
CREATE TABLE estat_data_history (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  stats_data_id TEXT NOT NULL,
  action TEXT NOT NULL,
  user_id TEXT,
  metadata_snapshot TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (user_id) REFERENCES users(id)
);
CREATE TABLE IF NOT EXISTS "estat_ranking_values_old_backup" (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  stats_data_id TEXT NOT NULL,
  area_code TEXT NOT NULL,
  value TEXT NOT NULL,
  numeric_value REAL,
  display_value TEXT,
  rank INTEGER,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  unit TEXT,
  area_name TEXT,
  category_code TEXT,
  category_name TEXT,
  time_code TEXT,
  time_name TEXT,
  UNIQUE(stats_data_id, category_code, time_code, area_code)
);
CREATE TABLE d1_migrations(
		id         INTEGER PRIMARY KEY AUTOINCREMENT,
		name       TEXT UNIQUE,
		applied_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL
);
CREATE TABLE data_sources (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  description TEXT,
  base_url TEXT,
  api_version TEXT,
  is_active BOOLEAN DEFAULT 1,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE IF NOT EXISTS "ranking_items" (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  ranking_key TEXT UNIQUE NOT NULL,  
  label TEXT NOT NULL,               
  name TEXT NOT NULL,                
  description TEXT,                   
  unit TEXT NOT NULL,                

  
  data_source_id TEXT NOT NULL,     

  
  map_color_scheme TEXT DEFAULT 'interpolateBlues',
  map_diverging_midpoint TEXT DEFAULT 'zero',
  ranking_direction TEXT DEFAULT 'desc',
  conversion_factor REAL DEFAULT 1,
  decimal_places INTEGER DEFAULT 0,

  is_active BOOLEAN DEFAULT 1,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,

  FOREIGN KEY (data_source_id) REFERENCES data_sources(id)
);
CREATE TABLE subcategory_ranking_items (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  subcategory_id TEXT NOT NULL,
  ranking_item_id INTEGER NOT NULL,
  display_order INTEGER DEFAULT 0,   
  is_default BOOLEAN DEFAULT 0,      
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,

  UNIQUE(subcategory_id, ranking_item_id),
  FOREIGN KEY (subcategory_id) REFERENCES subcategory_configs(id) ON DELETE CASCADE,
  FOREIGN KEY (ranking_item_id) REFERENCES "ranking_items"(id) ON DELETE CASCADE
);
CREATE TABLE data_source_metadata (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  ranking_item_id INTEGER NOT NULL,
  data_source_id TEXT NOT NULL,

  
  metadata TEXT NOT NULL,  
  
  

  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,

  UNIQUE(ranking_item_id, data_source_id),
  FOREIGN KEY (ranking_item_id) REFERENCES "ranking_items"(id) ON DELETE CASCADE,
  FOREIGN KEY (data_source_id) REFERENCES data_sources(id)
);
CREATE TABLE ranking_values (
  id INTEGER PRIMARY KEY AUTOINCREMENT,

  
  ranking_key TEXT NOT NULL,

  
  area_code TEXT NOT NULL,          
  area_name TEXT,                   

  
  time_code TEXT NOT NULL,          
  time_name TEXT,                   

  
  value TEXT NOT NULL,              
  numeric_value REAL,               
  display_value TEXT,                
  rank INTEGER,                     

  
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,

  
  UNIQUE(ranking_key, time_code, area_code),
  FOREIGN KEY (ranking_key) REFERENCES "ranking_items"(ranking_key) ON DELETE CASCADE
);
DELETE FROM sqlite_sequence;
CREATE INDEX idx_stats_data_id ON estat_metainfo(stats_data_id);
CREATE INDEX idx_stat_name ON estat_metainfo(stat_name);
CREATE INDEX idx_cat01 ON estat_metainfo(cat01);
CREATE INDEX idx_updated_at ON estat_metainfo(updated_at);
CREATE INDEX idx_ranking_viz_stats_id ON ranking_visualizations(stats_data_id);
CREATE INDEX idx_ranking_viz_cat01 ON ranking_visualizations(cat01);
CREATE UNIQUE INDEX idx_ranking_viz_composite ON ranking_visualizations(stats_data_id, cat01);
CREATE INDEX idx_choropleth_categories_display_order ON choropleth_categories(display_order);
CREATE INDEX idx_choropleth_categories_is_active ON choropleth_categories(is_active);
CREATE INDEX idx_choropleth_subcategories_category_id ON choropleth_subcategories(category_id);
CREATE INDEX idx_choropleth_subcategories_display_order ON choropleth_subcategories(display_order);
CREATE INDEX idx_choropleth_subcategories_is_active ON choropleth_subcategories(is_active);
CREATE INDEX idx_choropleth_subcategories_stats_data_id ON choropleth_subcategories(stats_data_id);
CREATE INDEX idx_choropleth_data_cache_subcategory_year ON choropleth_data_cache(subcategory_id, year);
CREATE INDEX idx_choropleth_data_cache_expires_at ON choropleth_data_cache(expires_at);
CREATE INDEX idx_choropleth_data_cache_cached_at ON choropleth_data_cache(cached_at);
CREATE INDEX idx_choropleth_data_cache_is_sample ON choropleth_data_cache(is_sample);
CREATE INDEX idx_prefectures_region ON prefectures(region);
CREATE INDEX idx_prefectures_is_active ON prefectures(is_active);
CREATE INDEX idx_choropleth_access_logs_created_at ON choropleth_access_logs(created_at);
CREATE INDEX idx_choropleth_access_logs_subcategory_id ON choropleth_access_logs(subcategory_id);
CREATE INDEX idx_choropleth_access_logs_cache_hit ON choropleth_access_logs(cache_hit);
CREATE INDEX idx_choropleth_user_settings_user_id ON choropleth_user_settings(user_id);
CREATE INDEX idx_estat_cat_lookup
  ON estat_categories(stats_data_id, category_code);
CREATE INDEX idx_estat_cat_stats_id
  ON estat_categories(stats_data_id);
CREATE INDEX idx_estat_time_lookup
  ON estat_time_periods(stats_data_id, time_code);
CREATE INDEX idx_estat_time_year
  ON estat_time_periods(stats_data_id, year DESC);
CREATE INDEX idx_estat_meta_lookup
  ON estat_cache_metadata(stats_data_id, category_code, time_code);
CREATE INDEX idx_estat_meta_expires
  ON estat_cache_metadata(expires_at);
CREATE INDEX idx_subcategory_configs_category ON subcategory_configs(category_id);
CREATE INDEX idx_ranking_items_subcategory ON "ranking_items_old_backup"(subcategory_id);
CREATE INDEX idx_ranking_items_active ON "ranking_items_old_backup"(is_active);
CREATE INDEX idx_ranking_items_display_order ON "ranking_items_old_backup"(display_order);
CREATE UNIQUE INDEX idx_ranking_items_unique ON "ranking_items_old_backup"(subcategory_id, ranking_key);
CREATE UNIQUE INDEX idx_accounts_provider ON accounts(provider, providerAccountId);
CREATE INDEX idx_sessions_userId ON sessions(userId);
CREATE INDEX idx_sessions_sessionToken ON sessions(sessionToken);
CREATE INDEX idx_users_username ON users(username);
CREATE INDEX idx_users_email ON users(email);
CREATE INDEX idx_history_stats_id ON estat_data_history(stats_data_id);
CREATE INDEX idx_history_user_id ON estat_data_history(user_id);
CREATE INDEX idx_estat_ranking_lookup 
  ON "estat_ranking_values_old_backup"(stats_data_id, category_code, time_code);
CREATE INDEX idx_estat_ranking_area 
  ON "estat_ranking_values_old_backup"(area_code);
CREATE INDEX idx_subcategory_ranking_subcategory ON subcategory_ranking_items(subcategory_id);
CREATE INDEX idx_subcategory_ranking_item ON subcategory_ranking_items(ranking_item_id);
CREATE INDEX idx_subcategory_ranking_order ON subcategory_ranking_items(subcategory_id, display_order);
CREATE INDEX idx_data_source_metadata_ranking ON data_source_metadata(ranking_item_id);
CREATE INDEX idx_data_source_metadata_source ON data_source_metadata(data_source_id);
CREATE INDEX idx_ranking_values_lookup ON ranking_values(ranking_key, time_code);
CREATE INDEX idx_ranking_values_area ON ranking_values(area_code);
CREATE INDEX idx_ranking_values_time ON ranking_values(time_code);
CREATE INDEX idx_estat_metainfo_ranking_key ON estat_metainfo(ranking_key);
CREATE TRIGGER tr_choropleth_categories_updated_at
  AFTER UPDATE ON choropleth_categories
  FOR EACH ROW
BEGIN
  UPDATE choropleth_categories
  SET updated_at = CURRENT_TIMESTAMP
  WHERE id = NEW.id;
END;
CREATE TRIGGER tr_choropleth_subcategories_updated_at
  AFTER UPDATE ON choropleth_subcategories
  FOR EACH ROW
BEGIN
  UPDATE choropleth_subcategories
  SET updated_at = CURRENT_TIMESTAMP
  WHERE id = NEW.id;
END;
CREATE TRIGGER tr_choropleth_data_cache_access
  AFTER UPDATE OF access_count ON choropleth_data_cache
  FOR EACH ROW
BEGIN
  UPDATE choropleth_data_cache
  SET last_accessed_at = CURRENT_TIMESTAMP
  WHERE id = NEW.id;
END;
CREATE VIEW estat_metainfo_unique AS
SELECT 
  MIN(id) as id,
  stats_data_id, 
  stat_name, 
  title,
  ranking_key,
  MIN(created_at) as created_at,
  MAX(updated_at) as updated_at,
  COUNT(*) as item_count
FROM estat_metainfo
WHERE stats_data_id IS NOT NULL
GROUP BY stats_data_id, stat_name, title;